def solution():
    # Use the three-argument form of pow() for efficient modular exponentiation
    # pow(base, exp, mod) avoids creating the giant intermediate number
    MOD = 10**10
    power_val = pow(2, 7830457, MOD)
    result = (28433 * power_val + 1) % MOD

    # Ensure 10 digits with leading zeros if necessary
    return str(result).zfill(10)


if __name__ == "__main__":
    print(solution())
